from typing import Dict, Optional, Any
import re

class Term:
    """Base class for terms (variables and constants)"""
    def __init__(self, name: str):
        self.name = name

    def is_variable(self) -> bool:
        return self.name.startswith('?')

    def __repr__(self):
        return self.name

def occurs_check(var: Term, term: Term, subst: Dict[str, Any]) -> bool:
    """Check if variable occurs in term (prevents infinite structures)"""
    if term.is_variable():
        return var.name == term.name
    return False

def unify(t1: Term, t2: Term, subst: Optional[Dict[str, Term]] = None) -> Optional[Dict[str, Term]]:
    """
    Unify two terms using the unification algorithm.
    Returns substitution dict or None if unification fails.
    """
    if subst is None:
        subst = {}

    # If both terms are identical, return current substitution
    if t1.name == t2.name:
        return subst

    # If t1 is a variable, apply substitution and add binding
    if t1.is_variable():
        if t1.name in subst:
            return unify(subst[t1.name], t2, subst)
        if occurs_check(t1, t2, subst):
            return None  # Occurs check fails
        subst[t1.name] = t2
        return subst

    # If t2 is a variable
    if t2.is_variable():
        if t2.name in subst:
            return unify(t1, subst[t2.name], subst)
        if occurs_check(t2, t1, subst):
            return None
        subst[t2.name] = t1
        return subst

    return None  # Cannot unify different constants

# Test basic unification
if __name__ == "__main__":
    # Test cases
    print("=== Basic Unification Tests ===")

    # ?x = john
    result = unify(Term('?x'), Term('john'))
    print(f"Unify ?x with john: {result}")

    # ?x = john, ?x = john
    result = unify(Term('?x'), Term('john'), {'?x': Term('john')})
    print(f"Unify ?x (already bound to john) with john: {result}")

    # ?x = ?y (both variables)
    result = unify(Term('?x'), Term('?y'))
    print(f"Unify ?x with ?y: {result}")

    # john = mary (should fail)
    result = unify(Term('john'), Term('mary'))
    print(f"Unify john with mary: {result}")

from typing import Dict, List, Optional, Set
from dataclasses import dataclass

@dataclass
class Literal:
    """Represents a literal (predicate with optional negation)"""
    predicate: str
    args: List[str]
    negated: bool = False

    def __repr__(self):
        sign = "¬" if self.negated else ""
        return f"{sign}{self.predicate}({', '.join(self.args)})"

def apply_substitution(literal: Literal, subst: Dict[str, str]) -> Literal:
    """Apply substitution to all arguments of a literal"""
    new_args = [subst.get(arg, arg) for arg in literal.args]
    return Literal(literal.predicate, new_args, literal.negated)

def compose_substitutions(s1: Dict[str, str], s2: Dict[str, str]) -> Dict[str, str]:
    """Compose two substitutions: s1 ○ s2 (apply s2 then s1)"""
    result = {}

    # Apply s2, then s1
    for var, term in s2.items():
        result[var] = s1.get(term, term)

    # Add variables only in s1
    for var, term in s1.items():
        if var not in s2:
            result[var] = term

    return result

def resolve_literals(l1: Literal, l2: Literal) -> Optional[Dict[str, str]]:
    """
    Resolve two complementary literals.
    Returns substitution if resolvable, None otherwise.
    """
    # Check if literals can resolve (same predicate, opposite signs)
    if l1.predicate != l2.predicate or l1.negated == l2.negated:
        return None

    # Simple unification of arguments
    subst = {}
    for arg1, arg2 in zip(l1.args, l2.args):
        if arg1 == arg2:
            continue
        if arg1.startswith('?'):
            subst[arg1] = arg2
        elif arg2.startswith('?'):
            subst[arg2] = arg1
        elif arg1 != arg2:
            return None  # Cannot unify constants

    return subst

def resolve_clauses(clause1: List[Literal], clause2: List[Literal]) -> List[Literal]:
    """
    Resolve two clauses to produce resolvent.
    Clause = disjunction of literals
    """
    resolvents = []

    for l1 in clause1:
        for l2 in clause2:
            subst = resolve_literals(l1, l2)
            if subst is not None:
                # Build resolvent (all literals except resolved pair)
                new_clause = []
                for l in clause1:
                    if l is not l1:
                        new_clause.append(apply_substitution(l, subst))
                for l in clause2:
                    if l is not l2:
                        new_clause.append(apply_substitution(l, subst))
                resolvents.append(new_clause)

    return resolvents

# Demo
if __name__ == "__main__":
    print("=== Substitution and Resolution Demo ===\n")

    # Clause 1: ¬Loves(x, y) ∨ Loves(y, x)  (if x loves y, y loves x)
    clause1 = [
        Literal('Loves', ['?x', '?y'], negated=True),
        Literal('Loves', ['?y', '?x'], negated=False)
    ]

    # Clause 2: ¬Loves(john, mary)  (john does not love mary)
    clause2 = [
        Literal('Loves', ['john', 'mary'], negated=True)
    ]

    print(f"Clause 1: {' ∨ '.join(map(str, clause1))}")
    print(f"Clause 2: {' ∨ '.join(map(str, clause2))}")

    resolvents = resolve_clauses(clause1, clause2)

    print(f"\nResolvents:")
    for r in resolvents:
        if r:
            print(f"  {' ∨ '.join(map(str, r))}")
        else:
            print("  □ (empty clause - contradiction found!)")

from typing import List, Dict, Set, Optional, Tuple
from dataclasses import dataclass, field
import re

@dataclass
class Clause:
    """A clause as a set of literals (stored as list)"""
    literals: List[Tuple[str, List[str], bool]]  # (predicate, args, negated)

    def __hash__(self):
        return hash(tuple(sorted(self.literals)))

    def __eq__(self, other):
        return set(self.literals) == set(other.literals)

def parse_clause(clause_str: str) -> Clause:
    """Parse a clause string like '¬Loves(x,y) ∨ Loves(y,x)' into Clause object"""
    # Remove spaces
    clause_str = clause_str.replace(" ", "")

    # Split by ∨
    literal_strs = clause_str.split("∨")

    literals = []
    for lit in literal_strs:
        negated = lit.startswith("¬")
        if negated:
            lit = lit[1:]

        # Extract predicate and arguments
        match = re.match(r'(\w+)\(([^)]+)\)', lit)
        if match:
            pred = match.group(1)
            args = [a.strip() for a in match.group(2).split(',')]
            literals.append((pred, args, negated))

    return Clause(literals)

def unify_args(args1: List[str], args2: List[str]) -> Optional[Dict[str, str]]:
    """Unify two argument lists"""
    if len(args1) != len(args2):
        return None

    subst = {}
    for a1, a2 in zip(args1, args2):
        if a1 == a2:
            continue
        if a1.startswith('?'):
            if a1 in subst and subst[a1] != a2:
                return None
            subst[a1] = a2
        elif a2.startswith('?'):
            if a2 in subst and subst[a2] != a1:
                return None
            subst[a2] = a1
        else:
            return None
    return subst

def resolve(c1: Clause, c2: Clause) -> List[Clause]:
    """Resolve two clauses"""
    resolvents = []

    for pred1, args1, neg1 in c1.literals:
        for pred2, args2, neg2 in c2.literals:
            # Check if resolvable (same predicate, opposite polarity)
            if pred1 != pred2 or neg1 == neg2:
                continue

            subst = unify_args(args1, args2)
            if subst is None:
                continue

            # Build resolvent
            new_literals = []
            for p, a, n in c1.literals:
                if p == pred1 and a == args1 and n == neg1:
                    continue
                # Apply substitution
                new_args = [subst.get(arg, arg) for arg in a]
                new_literals.append((p, new_args, n))

            for p, a, n in c2.literals:
                if p == pred2 and a == args2 and n == neg2:
                    continue
                new_args = [subst.get(arg, arg) for arg in a]
                new_literals.append((p, new_args, n))

            # Simplify: remove duplicates
            new_literals = list(set(new_literals))
            resolvents.append(Clause(new_literals))

    return resolvents

def resolution_prover(facts: List[str], goal: str, max_iterations: int = 100) -> Optional[List[Clause]]:
    """
    Resolution theorem prover.
    Returns proof (list of clauses leading to empty clause) or None.
    """
    # Parse facts and convert goal to negated clause
    clauses = set(parse_clause(f) for f in facts)

    # Negate goal and add to clauses
    negated_goal = "¬" + goal
    clauses.add(parse_clause(negated_goal))

    proof = []  # Track resolution steps

    for iteration in range(max_iterations):
        new_clauses = set()

        # Try all pairs
        clause_list = list(clauses)
        for i, c1 in enumerate(clause_list):
            for c2 in clause_list[i+1:]:
                resolvents = resolve(c1, c2)

                for r in resolvents:
                    if len(r.literals) == 0:  # Empty clause found!
                        proof.append(c1)
                        proof.append(c2)
                        proof.append(r)
                        return proof

                    if r not in clauses:
                        new_clauses.add(r)

        if not new_clauses:
            return None  # No more clauses can be derived

        clauses.update(new_clauses)

    return None

# Example: Prove that Socrates is mortal
if __name__ == "__main__":
    print("=== Resolution Theorem Prover ===\n")

    # Knowledge base (facts and rules):
    # 1. All men are mortal: ¬Man(x) ∨ Mortal(x)
    # 2. Socrates is a man: Man(socrates)
    # Goal: Prove Socrates is mortal: Mortal(socrates)

    facts = [
        "¬Man(x) ∨ Mortal(x)",  # All men are mortal
        "Man(socrates)"          # Socrates is a man
    ]

    goal = "Mortal(socrates)"

    print("Facts:")
    for f in facts:
        print(f"  {f}")
    print(f"\nGoal: Prove {goal}\n")

    proof = resolution_prover(facts, goal)

    if proof:
        print("✓ PROOF FOUND!")
        print("\nResolution steps:")
        for i, clause in enumerate(proof):
            if clause.literals:
                print(f"  {i+1}. {clause.literals}")
            else:
                print(f"  {i+1}. □ (empty clause - contradiction)")
    else:
        print("✗ Cannot prove the goal")
